function solve(n: number, k: number): number {
    // Precompute the popcount-depth for numbers up to 63 bits
    // Since n can be up to 1e15, we need to handle large numbers efficiently
    // We'll use memoization to avoid recomputing depths

    const memo: Map<number, number> = new Map();

    function popcountDepth(x: number): number {
        if (memo.has(x)) {
            return memo.get(x)!;
        }
        if (x === 1) {
            memo.set(x, 1);
            return 1;
        }
        const nextVal = x.toString(2).split('1').length - 1;
        const depth = 1 + popcountDepth(nextVal);
        memo.set(x, depth);
        return depth;
    }

    // Count numbers in [1, n] with popcount-depth exactly k
    let count = 0;
    for (let x = 1; x <= n; x++) {
        if (popcountDepth(x) === k) {
            count++;
        }
    }
    return count;
}
